import React from 'react';

type JobProgressBarProps = {
  percent?: number | null;
  done?: number | null;
  total?: number | null;
  unit?: 'sets' | 'documents' | string | null;
  compact?: boolean;
};

export const JobProgressBar: React.FC<JobProgressBarProps> = ({
  percent,
  done,
  total,
  unit,
  compact = false,
}) => {
  if (percent == null && (done == null || total == null))
    return <span style={{ color: '#94a3b8' }}>—</span>;

  const value = percent ?? (total && total > 0 ? Math.round(((done ?? 0) / total) * 100) : 0);
  const unitLabel = unit === 'sets' ? ' set' : unit === 'documents' ? ' doc' : '';
  const label =
    done != null && total != null
      ? `${done}/${total}${unitLabel} (${value}%)`
      : `${value}%`;

  return (
    <div style={{ minWidth: compact ? 100 : 140 }}>
      <div
        style={{
          height: 6,
          background: '#e2e8f0',
          borderRadius: 4,
          overflow: 'hidden',
        }}
      >
        <div
          style={{
            width: `${Math.min(100, Math.max(0, value))}%`,
            height: '100%',
            background: '#2563eb',
            transition: 'width 0.3s ease',
          }}
        />
      </div>
      {!compact ? (
        <span style={{ fontSize: 12, color: '#64748b' }}>{label}</span>
      ) : done != null && total != null ? (
        <span style={{ fontSize: 11, color: '#64748b' }}>
          {done}/{total}
          {unitLabel} ({value}%)
        </span>
      ) : (
        <span style={{ fontSize: 11, color: '#64748b' }}>{value}%</span>
      )}
    </div>
  );
};
