import React from 'react';
import { createPortal } from 'react-dom';
import styles from './DataSyncSetConfigPage.module.css';

type Props = {
  htmlFor?: string;
  label: string;
  tooltip?: string;
  required?: boolean;
};

const TOOLTIP_GAP = 6;

export const ConnectorFieldLabel: React.FC<Props> = ({ htmlFor, label, tooltip, required }) => {
  const tooltipId = React.useId();
  const triggerRef = React.useRef<HTMLSpanElement>(null);
  const [open, setOpen] = React.useState(false);
  const [pos, setPos] = React.useState({ top: 0, left: 0 });

  const updatePosition = React.useCallback(() => {
    const el = triggerRef.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    setPos({
      top: rect.bottom + TOOLTIP_GAP,
      left: Math.min(rect.left, window.innerWidth - 280),
    });
  }, []);

  const show = React.useCallback(() => {
    if (!tooltip) return;
    updatePosition();
    setOpen(true);
  }, [tooltip, updatePosition]);

  const hide = React.useCallback(() => setOpen(false), []);

  React.useEffect(() => {
    if (!open) return undefined;
    const onScrollOrResize = () => updatePosition();
    window.addEventListener('scroll', onScrollOrResize, true);
    window.addEventListener('resize', onScrollOrResize);
    return () => {
      window.removeEventListener('scroll', onScrollOrResize, true);
      window.removeEventListener('resize', onScrollOrResize);
    };
  }, [open, updatePosition]);

  return (
    <>
      <div
        className={styles.fieldLabelRow}
        onMouseEnter={show}
        onMouseLeave={hide}
        onFocus={show}
        onBlur={hide}
      >
        <label htmlFor={htmlFor} className={styles.fieldLabel}>
          {label}
          {required ? <span className={styles.requiredMark}> *</span> : null}
        </label>
        {tooltip ? (
          <span
            ref={triggerRef}
            className={styles.fieldTooltip}
            tabIndex={0}
            role="button"
            aria-label={`Giải thích: ${label}`}
            aria-describedby={open ? tooltipId : undefined}
            onMouseEnter={show}
            onMouseLeave={hide}
            onFocus={show}
            onBlur={hide}
          >
            ?
          </span>
        ) : null}
      </div>
      {tooltip && open
        ? createPortal(
            <div
              id={tooltipId}
              role="tooltip"
              className={styles.fieldTooltipPopup}
              style={{ top: pos.top, left: pos.left }}
            >
              {tooltip}
            </div>,
            document.body,
          )
        : null}
    </>
  );
};

export default ConnectorFieldLabel;
