import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAppSelector } from '../../store/hooks';
import { ForbiddenPage, hasValidAuthToken } from '@linm-soft/common-components';
import { useAdminPermissions } from '../../hooks/useAdminPermissions';
import { isStandalone } from '../../dev/isStandalone';
import { isAdminPermissionsBypass } from '../../dev/isAdminPermissionsBypass';

interface ProtectedRouteProps {
  children: React.ReactNode;
}

/**
 * Route guard for admin MFE.
 *
 * Guard order:
 *  1. Not authenticated → redirect to /login
 *  2. Permissions loading → show spinner
 *  3. Path not in user's navItems → ForbiddenPage
 *  4. Authenticated + authorised → render children
 */
export const ProtectedRoute: React.FC<ProtectedRouteProps> = ({ children }) => {
  const { isAuthenticated } = useAppSelector((state) => state.auth);
  const location = useLocation();
  const { loading, hasMenuAccess } = useAdminPermissions();

  // 1. Not authenticated or token cleared/tampered without Redux refresh
  if (!isStandalone && (!isAuthenticated || !hasValidAuthToken())) {
    return <Navigate to="/login" replace />;
  }

  // 2. Still fetching permission payload (standalone seeds full access in hook)
  if (!isAdminPermissionsBypass() && loading) {
    return (
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', minHeight: 200 }}>
        <i className="fas fa-spinner fa-spin" style={{ fontSize: 24, color: 'var(--primary-color, #2563eb)' }} />
      </div>
    );
  }

  // 3. Path not covered by the user's allowedPaths / navItems → Forbidden
  const isAdminPath = location.pathname.startsWith('/admin');
  let accessPath = location.pathname;
  if (accessPath === '/admin/packages') accessPath = '/admin/permissions';
  else if (accessPath === '/admin/') accessPath = '/admin';
  if (isAdminPath && !isAdminPermissionsBypass() && !hasMenuAccess(accessPath)) {
    return <ForbiddenPage />;
  }

  // 4. Authorised
  return <>{children}</>;
};
