import React from 'react';
import type { JobScheduleRuntimeStatus } from '../../services/jobs';

const STATUS_STYLE: Record<
  JobScheduleRuntimeStatus,
  { bg: string; color: string; border: string }
> = {
  Running: { bg: '#dbeafe', color: '#1d4ed8', border: '#93c5fd' },
  Sleep: { bg: '#ecfdf5', color: '#047857', border: '#6ee7b7' },
  Complete: { bg: '#f0fdf4', color: '#15803d', border: '#86efac' },
  Stopped: { bg: '#f1f5f9', color: '#475569', border: '#cbd5e1' },
};

type Props = {
  status?: JobScheduleRuntimeStatus;
  label?: string;
  message?: string | null;
  activeCount?: number;
};

export const JobScheduleStatusBadge: React.FC<Props> = ({
  status = 'Sleep',
  label,
  message,
  activeCount,
}) => {
  const style = STATUS_STYLE[status] ?? STATUS_STYLE.Sleep;
  const text = label ?? status;

  return (
    <div>
      <span
        style={{
          display: 'inline-block',
          fontSize: 12,
          fontWeight: 600,
          padding: '2px 8px',
          borderRadius: 999,
          background: style.bg,
          color: style.color,
          border: `1px solid ${style.border}`,
        }}
        data-testid={`job-schedule-status-${status}`}
      >
        {text}
        {status === 'Running' && activeCount != null && activeCount > 0 ? ` (${activeCount})` : ''}
      </span>
      {message ? (
        <div style={{ fontSize: 11, color: '#64748b', marginTop: 4, maxWidth: 200 }}>{message}</div>
      ) : null}
    </div>
  );
};

export default JobScheduleStatusBadge;
