import React, { useCallback, useState } from 'react';
import { Link } from 'react-router-dom';
import { useAppToast } from '@linm-soft/common-components';
import type { DataSyncRunDetail, ExternalSyncVoucherSample } from '../../../services/jobs/dataSyncModels';
import {
  JobDetailCollapsibleSection,
  JobDetailMetaGrid,
  JobDetailMonoId,
  formatJobDate,
  type JobDetailMetaItem,
} from './JobDetailMetaGrid';
import { truncateExternalErrorPreview } from './ExternalSyncCheckpointErrorModal';
import {
  connectorLabel,
  dedupeExternalErrorSamples,
  formatExternalRunStatsLine,
  resolveExternalRunDisplayStatus,
} from '../externalSyncRunDisplay';
import styles from '../JobInternalPage.module.css';
import { displayExternalRunStatus, jobStatusColor } from '../jobStatusDisplay';
import { isExternalSyncVoucherLinkable } from '../externalSyncVoucherViewPath';
import { openConvertedExternalSyncVoucher } from '../externalSyncVoucherNavigate';
import { buildJobsEventsHref } from '../jobsEventLinks';

export type JobExternalSyncRunDetailPanelProps = {
  runDetail: DataSyncRunDetail;
};

export const JobExternalSyncRunDetailPanel: React.FC<JobExternalSyncRunDetailPanelProps> = ({
  runDetail,
}) => {
  const toast = useAppToast();
  const [openingVoucherKey, setOpeningVoucherKey] = useState<string | null>(null);
  const conversion = runDetail.conversionSummary;

  const openConvertedVoucher = useCallback(
    async (sample: ExternalSyncVoucherSample) => {
      const code = sample.voucherCode?.trim();
      if (!code || !isExternalSyncVoucherLinkable(sample.setName, code)) return;

      const rowKey = `${sample.setName}-${sample.externalId}-${code}`;
      setOpeningVoucherKey(rowKey);
      try {
        await openConvertedExternalSyncVoucher(runDetail, sample);
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Không mở được chứng từ ERP.';
        toast.error(message);
      } finally {
        setOpeningVoucherKey(null);
      }
    },
    [runDetail, toast],
  );
  const displayStatus = resolveExternalRunDisplayStatus(runDetail);
  const companyLabel =
    conversion?.companyCode && conversion?.companyName
      ? `${conversion.companyCode} — ${conversion.companyName}`
      : conversion?.companyCode ??
        conversion?.companyName ??
        runDetail.companyCode ??
        runDetail.companyName ??
        runDetail.companyId;

  const connectorNames = runDetail.setsRequested.map(connectorLabel);
  const checkpoint = runDetail.checkpointSummary;
  const setResults = runDetail.setResults ?? [];
  const voucherSamples = runDetail.voucherSamples ?? [];
  const errorSamples = dedupeExternalErrorSamples(runDetail.errorSamples);
  const hasErrors = checkpoint.failed > 0 || errorSamples.length > 0;

  const statsLine = formatExternalRunStatsLine(runDetail);

  return (
    <>
      <div className={styles.detailSummaryHero} data-testid="external-sync-run-hero">
        <p className={styles.detailSummaryHeroTitle} style={{ color: jobStatusColor(displayStatus) }}>
          {runDetail.kind === 'ExternalRetry' ? 'Retry · ' : ''}
          {displayExternalRunStatus(displayStatus)}
          {conversion?.fromDate && conversion?.toDate
            ? ` · ${conversion.fromDate} → ${conversion.toDate}`
            : ''}
        </p>
        <p className={styles.detailSummaryHeroLine}>
          <strong>{companyLabel}</strong>
          {connectorNames.length > 0 ? ` · ${connectorNames.join(', ')}` : ''}
        </p>
        <p className={styles.detailSummaryHeroLine}>{statsLine}</p>
        {hasErrors ? (
          <p className={styles.detailSummaryHeroHint}>
            Có checkpoint Failed — xem mục lỗi bên dưới hoặc bảng checkpoint (cột Lỗi). Dùng{' '}
            <strong>Retry Failed</strong> để GET detail lại và import (run retry mới).
          </p>
        ) : displayStatus === 'Success' || displayStatus === 'Partial' ? (
          <p className={styles.detailSummaryHeroHint}>
            Run đã kết thúc. Mở các mục chi tiết bên dưới nếu cần xem mã CT hoặc kỹ thuật.
          </p>
        ) : null}
      </div>

      {errorSamples.length > 0 ? (
        <JobDetailCollapsibleSection
          title={`Lỗi sync (${errorSamples.length}${
            (runDetail.errorSamples?.length ?? 0) > errorSamples.length
              ? ` · ${runDetail.errorSamples?.length ?? 0} lần ghi`
              : ''
          })`}
          defaultOpen={false}
        >
          <p className={styles.detailSummaryHeroHint} style={{ marginTop: 0 }}>
            Mỗi mã chứng từ hiển thị lỗi mới nhất. Bấm tiêu đề để mở/đóng bảng.
          </p>
          <div className={styles.detailTableWrap}>
            <table className={styles.detailTable}>
              <thead>
                <tr>
                  <th align="left">Mã chứng từ</th>
                  <th align="left">Thông báo</th>
                  <th align="left">Thời điểm</th>
                </tr>
              </thead>
              <tbody>
                {errorSamples.map((e, idx) => (
                  <tr key={`${e.documentKey}-${idx}`}>
                    <td className={styles.gridMono}>{e.documentKey || '—'}</td>
                    <td style={{ color: '#b91c1c', whiteSpace: 'pre-wrap' }} title={e.message}>
                      {truncateExternalErrorPreview(e.message, 160)}
                    </td>
                    <td style={{ color: '#64748b' }}>{e.atUtc ? formatJobDate(e.atUtc) : '—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </JobDetailCollapsibleSection>
      ) : null}

      <JobDetailCollapsibleSection title="Chi tiết kỹ thuật (run id, trigger, thời gian)" defaultOpen={false}>
        <JobDetailMonoId>{runDetail.id}</JobDetailMonoId>
        <JobDetailMetaGrid
          items={[
            {
              label: 'Trạng thái',
              value: (
                <span style={{ color: jobStatusColor(displayStatus) }}>
                  {displayExternalRunStatus(displayStatus)}
                </span>
              ),
            },
            { label: 'Trigger', value: runDetail.trigger },
            { label: 'Kind', value: runDetail.kind },
            ...(runDetail.parentRunId
              ? [
                  {
                    label: 'Run gốc',
                    value: (
                      <Link
                        to={`/admin/jobs/external-runs?runId=${runDetail.parentRunId}`}
                        className={styles.linkButton}
                      >
                        {runDetail.parentRunId}
                      </Link>
                    ),
                    mono: true,
                    fullWidth: true,
                  } satisfies JobDetailMetaItem,
                ]
              : []),
            { label: 'Environment', value: runDetail.environmentName },
            { label: 'Tiến độ', value: `${runDetail.progressPercent}%` },
            { label: 'Bắt đầu', value: formatJobDate(runDetail.startedAtUtc) },
            { label: 'Kết thúc', value: formatJobDate(runDetail.finishedAtUtc) ?? '—' },
          ] satisfies JobDetailMetaItem[]}
        />
      </JobDetailCollapsibleSection>

      {setResults.length > 0 ? (
        <JobDetailCollapsibleSection
          title={`Kết quả theo loại chứng từ (${setResults.length})`}
          defaultOpen={hasErrors}
        >
          <div className={styles.detailTableWrap}>
            <table className={styles.detailTable}>
              <thead>
                <tr>
                  <th>Loại</th>
                  <th>Connector</th>
                  <th>Trạng thái</th>
                  <th align="right">Convert</th>
                  <th align="right">Pull only</th>
                  <th align="right">Lỗi</th>
                  <th align="right">Tổng</th>
                </tr>
              </thead>
              <tbody>
                {setResults.map((s) => (
                  <tr key={s.setName}>
                    <td>{s.voucherTypeLabel}</td>
                    <td className={styles.gridMono}>{s.setName}</td>
                    <td style={{ color: jobStatusColor(s.status) }}>
                      {displayExternalRunStatus(s.status)}
                    </td>
                    <td align="right">{s.documentsConverted.toLocaleString('vi-VN')}</td>
                    <td align="right">
                      {s.documentsPullOnly > 0 ? s.documentsPullOnly.toLocaleString('vi-VN') : '—'}
                    </td>
                    <td align="right" style={{ color: s.documentsFailed > 0 ? '#b91c1c' : undefined }}>
                      {s.documentsFailed > 0 ? s.documentsFailed.toLocaleString('vi-VN') : '—'}
                    </td>
                    <td align="right">{s.documentsTotal.toLocaleString('vi-VN')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </JobDetailCollapsibleSection>
      ) : null}

      {voucherSamples.length > 0 ? (
        <JobDetailCollapsibleSection title={`Mã chứng từ đã convert (${voucherSamples.length})`}>
          <div className={styles.detailTableWrap}>
            <table className={styles.detailTable}>
              <thead>
                <tr>
                  <th>Loại</th>
                  <th>Mã POS</th>
                  <th>Mã CT ERP</th>
                  <th>Mới</th>
                </tr>
              </thead>
              <tbody>
                {voucherSamples.map((v, idx) => {
                  const code = v.voucherCode?.trim() ?? '';
                  const linkable = code.length > 0 && isExternalSyncVoucherLinkable(v.setName, code);
                  const rowKey = `${v.setName}-${v.externalId}-${code || idx}`;
                  const opening = openingVoucherKey === rowKey;
                  return (
                  <tr key={rowKey}>
                    <td>{connectorLabel(v.setName)}</td>
                    <td className={styles.gridMono}>{v.externalId}</td>
                    <td className={styles.gridMono}>
                      {linkable ? (
                        <button
                          type="button"
                          className={styles.linkButton}
                          title="Mở chứng từ ERP (tab mới)"
                          disabled={opening}
                          data-testid={`external-sync-voucher-view-${idx}`}
                          onClick={() => void openConvertedVoucher(v)}
                        >
                          {opening ? 'Đang mở…' : code}
                        </button>
                      ) : (
                        v.voucherCode ?? '—'
                      )}
                    </td>
                    <td>{v.isNewInsert ? 'Có' : v.isNewInsert === false ? '—' : '?'}</td>
                  </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </JobDetailCollapsibleSection>
      ) : null}

      <JobDetailCollapsibleSection title="Tiến độ & checkpoint" defaultOpen={runDetail.status === 'Running'}>
        {runDetail.progress ? (
          <ul style={{ margin: '0 0 12px', paddingLeft: 18, fontSize: 13 }}>
            {runDetail.progress.sets.map((s) => (
              <li key={s.setName}>
                {connectorLabel(s.setName)}: {s.documentsDone}/{s.documentsTotal} xong
                {s.documentsFailed > 0 ? `, ${s.documentsFailed} lỗi` : ''}
                {s.documentsPending > 0 ? `, ${s.documentsPending} chờ` : ''} ({s.progressPercent}%)
              </li>
            ))}
          </ul>
        ) : (
          <p style={{ color: '#64748b', fontSize: 13, marginTop: 0 }}>Chưa có checkpoint progress.</p>
        )}
        <JobDetailMetaGrid
          items={[
            { label: 'Tổng checkpoint', value: checkpoint.total },
            { label: 'Done', value: checkpoint.done },
            { label: 'Processing', value: checkpoint.processing },
            { label: 'Pending', value: checkpoint.pending },
            { label: 'Failed', value: checkpoint.failed },
          ]}
        />
      </JobDetailCollapsibleSection>

      {runDetail.status === 'Running' ? (
        <p style={{ fontSize: 12, color: '#64748b', margin: '0 0 12px' }}>
          Run đang chạy — tự làm mới mỗi 4 giây.
        </p>
      ) : null}

      <Link
        to={buildJobsEventsHref({ direction: 'Inbound', runId: runDetail.id })}
        style={{ fontSize: 13 }}
      >
        Xem events Inbound (run {runDetail.id.slice(0, 8)}…) →
      </Link>
    </>
  );
};
