/** Mô tả nghiệp vụ — hiển thị trên Admin Job schedule / events. */
export const JOB_EVENT_DESCRIPTIONS: Record<string, string> = {
  'Document.PostImportRequested':
    'Ghi sổ chứng từ sau import/sync — Low tier. Tạm dừng qua Admin external sync → Kiểm soát ghi sổ.',
  'DataSync.ExternalSyncRequested':
    'Phase A — Pull REVA/connector: probe search pageSize=1 → đếm totalItems, tính totalPages, enqueue cửa sổ trang search. Kích hoạt: Admin External sync «Tạo yêu cầu sync», POST …/external/…/run, hoặc lịch job «Pull connector — init count».',
  'DataSync.ExternalSearchPageRequested':
    'Phase B — Gọi search 1 trang (TimHoaDon/TimPhieuThu/TimPhieuChi…), mỗi dòng tạo checkpoint + enqueue detail. Tự sinh từ phase A; chạy song song theo parallelJobs.',
  'DataSync.ExternalDetailRequested':
    'Phase C — GET chi tiết (hoặc dùng row search) → import ERP qua endpointRouteTemplate. 1 event = 1 chứng từ (hóa đơn, phiếu thu/chi). Tự sinh từ phase B.',
  'DataSync.InboundReceived':
    'Webhook push — hệ ngoài POST batch vào BFF/API …/data-sync/inbound/{connectorKey}. Hiện cập nhật data_sync_runs; import từng item (P2).',
  'DataSync.SeedRequested':
    'Import CSV master/seed từ data/master/sets — enqueue qua MasterDataImportRuns. Startup hoặc lịch Admin.',
  'MasterData.ImportRequested':
    'Legacy alias seed import — tương tự DataSync.SeedRequested.',
};

export const getJobEventDescription = (eventType: string): string | undefined =>
  JOB_EVENT_DESCRIPTIONS[eventType];

export const getJobTriggerHint = (eventType: string): string | undefined => {
  switch (eventType) {
    case 'DataSync.ExternalSyncRequested':
      return 'Kích hoạt thủ công: /admin/jobs/external-sync → Tạo yêu cầu sync';
    case 'DataSync.ExternalSearchPageRequested':
    case 'DataSync.ExternalDetailRequested':
      return 'Tự động — không chạy tay từ lịch (con của pull sync)';
    case 'DataSync.InboundReceived':
      return 'Kích hoạt: POST web-bff/…/data-sync/inbound/{connectorKey}';
    default:
      return undefined;
  }
};
