/**
 * SSOT — biến môi trường server cho job / platform events (Railway, Docker).
 *
 * **deploy** — ops cần cân nhắc trên Railway / hosting.
 * **system** — integrate lib + appsettings + EF migration (không liệt kê Railway).
 * **build** — chỉ lúc docker build.
 *
 * @see ERP/Linm.Web.ERP.WebService/docs/railway-deploy.md
 * @see API-LIB/LINM.Platform.Eventing/docs/install-service.md
 */

export type JobServerEnvGroupId =
  | 'database'
  | 'platform-eventing'
  | 'master-import'
  | 'external-reva'
  | 'docker-build'
  | 'system-lib';

export type JobServerEnvTier = 'deploy' | 'system' | 'build';

export interface JobServerEnvEntry {
  envKey: string;
  appsettingsPath: string;
  description: string;
  exampleValue: string;
  required: boolean;
  secret: boolean;
  tier: JobServerEnvTier;
  group: JobServerEnvGroupId;
  note?: string;
  /** Nguồn cấu hình hệ thống (lib / migration). */
  systemSource?: string;
}

