/** @deprecated use JOB_SERVER_ENV_DEPLOY_ENTRIES — giữ lookup envKey. */
export const JOB_SERVER_ENV_ENTRIES: JobServerEnvEntry[] = [
  ...JOB_SERVER_ENV_DEPLOY_ENTRIES.filter((e) => e.tier === 'deploy'),
  ...JOB_SERVER_ENV_SYSTEM_ENTRIES,
];

export function groupJobServerEnvEntries(
  entries: JobServerEnvEntry[],
): Map<JobServerEnvGroupId, JobServerEnvEntry[]> {
  const map = new Map<JobServerEnvGroupId, JobServerEnvEntry[]>();
  for (const g of JOB_SERVER_ENV_GROUPS) {
    map.set(g.id, []);
  }
  for (const entry of entries) {
    map.get(entry.group)?.push(entry);
  }
  return map;
}

export function formatEnvLine(entry: JobServerEnvEntry): string {
  return `${entry.envKey}=${entry.exampleValue}`;
}

export function formatEnvBlock(entries: JobServerEnvEntry[]): string {
  return entries.map(formatEnvLine).join('\n');
}

export function rowHighlightClass(
  status: string | undefined,
  styles: Record<string, string>,
): string {
  switch (status) {
    case 'Ready':
    case 'SystemOk':
      return styles.rowReady ?? '';
    case 'Missing':
      return styles.rowMissing ?? '';
    case 'Warning':
      return styles.rowWarning ?? '';
    case 'NotApplicable':
      return styles.rowBuild ?? '';
    default:
      return '';
  }
}
