import { getAuthToken, unwrap, type BffResponse } from '@linm-soft/common-components';
import { appSettings } from '../../config/appSettings';
import type { DataSyncRunDetail, ExternalSyncVoucherSample } from '../../services/jobs/dataSyncModels';
import { jobsEndpoint } from '../../services/jobs/jobsEndpoint';
import {
  isExternalSyncVoucherLinkable,
  resolveExternalSyncVoucherViewPath,
} from './externalSyncVoucherViewPath';

type PagedItems<T> = { items?: T[] };

type VoucherListRow = { id?: string; code?: string };

function runCompanyCode(runDetail: DataSyncRunDetail): string | null {
  const code =
    runDetail.conversionSummary?.companyCode?.trim() ||
    runDetail.companyCode?.trim() ||
    null;
  return code || null;
}

/** ERP shell origin for opening Finance/Sales routes in a new tab. */
export function getErpShellBaseUrl(): string {
  if (typeof window === 'undefined') return '';
  const { origin, hostname } = window.location;
  if (hostname === 'localhost' || hostname === '127.0.0.1') {
    const api = appSettings.apiUrl;
    if (api.includes('erp-bff.linm-soft.com') || api.includes('erp.linm-soft.com')) {
      return 'https://erp.linm-soft.com';
    }
    return origin;
  }
  return origin;
}

export function openErpVoucherInNewTab(viewPath: string): void {
  const base = getErpShellBaseUrl().replace(/\/$/, '');
  const path = viewPath.startsWith('/') ? viewPath : `/${viewPath}`;
  const opened = window.open(`${base}${path}`, '_blank', 'noopener,noreferrer');
  if (!opened) {
    throw new Error('Trình duyệt chặn cửa sổ mới. Cho phép popup rồi thử lại.');
  }
}

async function fetchTenantJson<T>(
  path: string,
  companyCode: string,
): Promise<T> {
  const token = getAuthToken();
  const url = `${appSettings.apiUrl}${path}`;
  const res = await fetch(url, {
    headers: {
      'Content-Type': 'application/json',
      'X-Timezone': Intl.DateTimeFormat().resolvedOptions().timeZone,
      'X-Company-Id': companyCode,
      ...(token ? { Authorization: `Bearer ${token}` } : {}),
    },
  });
  if (!res.ok) {
    let message = `API ${res.status}`;
    try {
      const body = await res.json();
      message = body?.error?.toastMessage || body?.message || message;
    } catch {
      // ignore
    }
    throw new Error(message);
  }
  return (await res.json()) as T;
}

function pickExactCode(rows: VoucherListRow[] | undefined, code: string): string | null {
  if (!rows?.length) return null;
  const exact = rows.find((r) => r.code?.trim() === code);
  return (exact?.id ?? rows[0]?.id)?.trim() || null;
}

async function lookupVoucherIdViaListApi(
  setName: string,
  code: string,
  companyCode: string,
): Promise<string | null> {
  const key = setName.trim().toLowerCase();
  const upper = code.toUpperCase();
  const qs = `search=${encodeURIComponent(code)}&page=1&pageSize=10`;

  if (key === 'reva-fm-hoa-don' || upper.startsWith('INV-')) {
    const res = await fetchTenantJson<BffResponse<PagedItems<VoucherListRow>>>(
      `/sales/invoices?${qs}`,
      companyCode,
    );
    return pickExactCode(unwrap(res).items, code);
  }

  if (key === 'reva-fm-phieu-thu' || upper.startsWith('PT-')) {
    const res = await fetchTenantJson<BffResponse<PagedItems<VoucherListRow>>>(
      `/accounting/receipts?${qs}`,
      companyCode,
    );
    return pickExactCode(unwrap(res).items, code);
  }

  if (key === 'reva-fm-phieu-chi' || upper.startsWith('PC-')) {
    const res = await fetchTenantJson<BffResponse<PagedItems<VoucherListRow>>>(
      `/accounting/payments?${qs}`,
      companyCode,
    );
    return pickExactCode(unwrap(res).items, code);
  }

  return null;
}

async function resolveVoucherId(
  runDetail: DataSyncRunDetail,
  sample: ExternalSyncVoucherSample,
  code: string,
): Promise<string | null> {
  const cached = sample.voucherId?.trim();
  if (cached) return cached;

  try {
    const admin = await jobsEndpoint.resolveExternalSyncVoucher(
      runDetail.id,
      sample.setName,
      code,
    );
    const fromAdmin = admin.voucherId?.trim();
    if (fromAdmin) return fromAdmin;
  } catch {
    // Prod có thể chưa có endpoint voucher-resolve — fallback list API
  }

  const companyCode = runCompanyCode(runDetail);
  if (!companyCode) return null;

  return lookupVoucherIdViaListApi(sample.setName, code, companyCode);
}

export async function openConvertedExternalSyncVoucher(
  runDetail: DataSyncRunDetail,
  sample: ExternalSyncVoucherSample,
): Promise<void> {
  const code = sample.voucherCode?.trim();
  if (!code || !isExternalSyncVoucherLinkable(sample.setName, code)) {
    throw new Error('Mã chứng từ không hỗ trợ mở form ERP.');
  }

  const voucherId = await resolveVoucherId(runDetail, sample, code);
  const viewPath = resolveExternalSyncVoucherViewPath(sample.setName, voucherId, code);
  if (!viewPath) {
    const company = runCompanyCode(runDetail);
    throw new Error(
      company
        ? `Không tìm thấy chứng từ ${code} (đơn vị ${company}).`
        : `Không tìm thấy chứng từ ${code}.`,
    );
  }

  openErpVoucherInNewTab(viewPath);
}
