import type { ImportRunSummary, ImportSetResult } from '../../services/jobs';

export interface ImportRecordStats {
  total: number;
  pass: number;
  fail: number;
  draft: number;
  skipped: number;
}

export function aggregateSetRecordStats(set: ImportSetResult): ImportRecordStats {
  return set.catalogs.reduce<ImportRecordStats>(
    (acc, c) => ({
      total: acc.total + c.rowsTotal,
      pass: acc.pass + c.rowsUpserted + c.rowsPosted,
      fail: acc.fail + c.rowsFailed,
      draft: acc.draft + c.rowsDraft,
      skipped: acc.skipped + c.rowsSkipped,
    }),
    { total: 0, pass: 0, fail: 0, draft: 0, skipped: 0 },
  );
}

export function aggregateRunRecordStats(
  summary: ImportRunSummary,
  setResults: ImportSetResult[] = [],
): ImportRecordStats {
  if (setResults.length > 0) {
    return setResults.reduce<ImportRecordStats>(
      (acc, set) => {
        const row = aggregateSetRecordStats(set);
        return {
          total: acc.total + row.total,
          pass: acc.pass + row.pass,
          fail: acc.fail + row.fail,
          draft: acc.draft + row.draft,
          skipped: acc.skipped + row.skipped,
        };
      },
      { total: 0, pass: 0, fail: 0, draft: 0, skipped: 0 },
    );
  }

  const catalogTotal = summary.catalogRowsTotal ?? 0;
  const catalogPass = summary.catalogRowsUpserted ?? 0;
  const catalogFail = summary.catalogRowsFailed ?? 0;
  const voucherTotal = summary.voucherHeadersTotal ?? 0;
  const voucherPass = summary.voucherHeadersPosted ?? 0;
  const voucherDraft = summary.voucherHeadersDraft ?? 0;

  return {
    total: catalogTotal + voucherTotal,
    pass: catalogPass + voucherPass,
    fail: catalogFail,
    draft: voucherDraft,
    skipped: 0,
  };
}

/** Human-readable pass/fail line for Partial / Failed runs. */
export function formatImportRecordStatsLine(stats: ImportRecordStats): string {
  const parts: string[] = [`${stats.pass.toLocaleString('vi-VN')} pass`, `${stats.fail.toLocaleString('vi-VN')} fail`];
  if (stats.draft > 0) {
    parts.push(`${stats.draft.toLocaleString('vi-VN')} draft`);
  }
  if (stats.skipped > 0) {
    parts.push(`${stats.skipped.toLocaleString('vi-VN')} skip`);
  }
  const totalSuffix = stats.total > 0 ? ` / ${stats.total.toLocaleString('vi-VN')} tổng` : '';
  return `Bản ghi: ${parts.join(' · ')}${totalSuffix}`;
}

export function formatImportSetsSummaryLine(summary: ImportRunSummary): string {
  const parts: string[] = [`${summary.setsSuccess}/${summary.setsTotal} ok`];
  if (summary.setsPartial > 0) {
    parts.push(`${summary.setsPartial} partial`);
  }
  if (summary.setsFailed > 0) {
    parts.push(`${summary.setsFailed} fail`);
  }
  if (summary.setsSkipped > 0) {
    parts.push(`${summary.setsSkipped} skip`);
  }
  return `Sets: ${parts.join(' · ')}`;
}

export const showImportRecordStats = (status: string): boolean =>
  status === 'Partial' || status === 'Failed';
