/** ERP form view path for REVA external sync converted vouchers. */
const CONNECTOR_VIEW_PATH: Record<string, (id: string) => string> = {
  'reva-fm-phieu-thu': (id) => `/kt/pt/${id}`,
  'reva-fm-phieu-chi': (id) => `/kt/pc/${id}`,
  'reva-fm-hoa-don': (id) => `/bh/hoa-don/${id}`,
};

const CODE_PREFIX_VIEW_PATH: Array<{ prefix: string; build: (id: string) => string }> = [
  { prefix: 'PT-', build: (id) => `/kt/pt/${id}` },
  { prefix: 'PC-', build: (id) => `/kt/pc/${id}` },
  { prefix: 'INV-', build: (id) => `/bh/hoa-don/${id}` },
];

function buildPathForSet(setName: string, voucherId: string): string | null {
  const key = setName.trim().toLowerCase();
  const byConnector = CONNECTOR_VIEW_PATH[key];
  if (byConnector) return byConnector(voucherId);
  return null;
}

function buildPathForCode(voucherCode: string, voucherId: string): string | null {
  const upper = voucherCode.trim().toUpperCase();
  for (const { prefix, build } of CODE_PREFIX_VIEW_PATH) {
    if (upper.startsWith(prefix)) return build(voucherId);
  }
  return null;
}

/** Whether Mã CT ERP can open an ERP form (by connector or code prefix). */
export function isExternalSyncVoucherLinkable(
  setName: string,
  voucherCode?: string | null,
): boolean {
  const key = setName.trim().toLowerCase();
  if (key in CONNECTOR_VIEW_PATH) return true;
  if (!voucherCode) return false;
  const upper = voucherCode.trim().toUpperCase();
  return CODE_PREFIX_VIEW_PATH.some(({ prefix }) => upper.startsWith(prefix));
}

/** Shell route to open ERP voucher form (Finance / Sales MFE). */
export function resolveExternalSyncVoucherViewPath(
  setName: string,
  voucherId?: string | null,
  voucherCode?: string | null,
): string | null {
  if (!voucherId) return null;
  const id = voucherId.trim();
  if (!id) return null;

  const bySet = buildPathForSet(setName, id);
  if (bySet) return bySet;

  if (voucherCode) {
    const byCode = buildPathForCode(voucherCode, id);
    if (byCode) return byCode;
  }

  return null;
}
