import React from 'react';
import { useAppToast } from '@linm-soft/common-components';
import { Button } from '../../ui';
import type {
  ExternalConnectorOptions,
  ExternalConnectorTestConnectResult,
  ExternalConnectorTestSearchResult,
  UpdateDataSyncSetConfigRequest,
} from '../../services/jobs';
import ConnectorFormField from './ConnectorFormField';
import ConnectorFieldLabel from './ConnectorFieldLabel';
import {
  CONNECTOR_CONFIG_PANELS,
  CONNECTOR_FIELD_TOOLTIPS,
  type ConnectorConfigPanel,
} from './connectorConfigTooltips';
import { JOB_SCHEDULE_TIMEZONES } from './scheduleRecurrenceUtils';
import { API_KEY_MASK } from './externalConnectorFormUtils';
import { CopyTextButton } from './CopyTextButton';
import {
  buildTestConnectAiDebugBundle,
  buildTestSearchAiDebugBundle,
} from './connectorDebugCopyUtils';
import styles from './DataSyncSetConfigPage.module.css';

type TestResponseState =
  | { kind: 'connect'; result: ExternalConnectorTestConnectResult }
  | { kind: 'search'; result: ExternalConnectorTestSearchResult };

export type ExternalConnectorConfigFormProps = {
  configKey: string;
  form: UpdateDataSyncSetConfigRequest;
  options: ExternalConnectorOptions;
  apiKeyInput: string;
  hasStoredApiKey: boolean;
  activePanel: ConnectorConfigPanel;
  testFromDate: string;
  testToDate: string;
  testResponse: TestResponseState | null;
  testingConnect: boolean;
  testingSearch: boolean;
  testingPreview: boolean;
  onActivePanelChange: (panel: ConnectorConfigPanel) => void;
  onFormChange: React.Dispatch<React.SetStateAction<UpdateDataSyncSetConfigRequest>>;
  onOptionsChange: React.Dispatch<React.SetStateAction<ExternalConnectorOptions>>;
  onApiKeyInputChange: (value: string) => void;
  onTestFromDateChange: (value: string) => void;
  onTestToDateChange: (value: string) => void;
  onTestConnect: () => void;
  onTestSearch: () => void;
  onTestPreview: () => void;
  onCreateSyncFromTest?: () => void;
  canCreateSyncFromTest?: boolean;
  lastTestTotalItems?: number;
  previewPanel?: React.ReactNode;
};

const renderTestResponse = (
  testResponse: TestResponseState | null,
  configKey: string,
  onCopyOk: () => void,
  onCopyErr: () => void,
) => {
  if (!testResponse) return null;

  const formatJsonForDisplay = (text: string): string => {
    try {
      return JSON.stringify(JSON.parse(text), null, 2);
    } catch {
      return text;
    }
  };

  const copyText =
    testResponse.kind === 'connect'
      ? buildTestConnectAiDebugBundle(testResponse.result, configKey)
      : buildTestSearchAiDebugBundle(testResponse.result, configKey);

  const displayText =
    testResponse.kind === 'connect'
      ? JSON.stringify(
          {
            success: testResponse.result.success,
            httpStatus: testResponse.result.httpStatus,
            message: testResponse.result.message,
            totalItems: testResponse.result.totalItems,
            elapsedMs: testResponse.result.elapsedMs,
            requestUrl: testResponse.result.requestUrl,
          },
          null,
          2,
        )
      : testResponse.result.responseJson
        ? formatJsonForDisplay(testResponse.result.responseJson)
        : formatJsonForDisplay(
            JSON.stringify(
              { message: testResponse.result.message, httpStatus: testResponse.result.httpStatus },
              null,
              2,
            ),
          );

  return (
    <div className={styles.testResponseWrap}>
      <div className={styles.testResponseActions}>
        <CopyTextButton
          text={copyText}
          label="Copy gói lỗi (AI)"
          testId="connector-test-copy-ai-debug"
          onCopied={onCopyOk}
          onError={onCopyErr}
        />
        <CopyTextButton
          text={displayText}
          label="Copy response"
          testId="connector-test-copy-response"
          onCopied={onCopyOk}
          onError={onCopyErr}
        />
      </div>
      <div
        className={`${styles.responseBlock} ${
          testResponse.result.success ? styles.responseOk : styles.responseErr
        }`}
        data-testid={
          testResponse.kind === 'connect'
            ? 'connector-test-connect-response'
            : 'connector-test-search-response'
        }
      >
        {displayText}
      </div>
    </div>
  );
};

export const ExternalConnectorConfigForm: React.FC<ExternalConnectorConfigFormProps> = ({
  configKey,
  form,
  options,
  apiKeyInput,
  hasStoredApiKey,
  activePanel,
  testFromDate,
  testToDate,
  testResponse,
  testingConnect,
  testingSearch,
  testingPreview,
  onActivePanelChange,
  onFormChange,
  onOptionsChange,
  onApiKeyInputChange,
  onTestFromDateChange,
  onTestToDateChange,
  onTestConnect,
  onTestSearch,
  onTestPreview,
  onCreateSyncFromTest,
  canCreateSyncFromTest = false,
  lastTestTotalItems,
  previewPanel,
}) => {
  const toast = useAppToast();
  const [apiKeyEdited, setApiKeyEdited] = React.useState(false);

  React.useEffect(() => {
    setApiKeyEdited(false);
  }, [configKey]);

  const showApiKeyMask = hasStoredApiKey && !apiKeyEdited;
  const apiKeyDisplayValue = showApiKeyMask ? API_KEY_MASK : apiKeyInput;

  return (
  <div className={styles.slideoutBody} data-testid="connector-config-slideout">
    <div className={styles.panelTabs} role="tablist" aria-label="Nhóm cấu hình connector">
      {CONNECTOR_CONFIG_PANELS.map((p) => (
        <button
          key={p.id}
          type="button"
          role="tab"
          aria-selected={activePanel === p.id}
          aria-controls={`connector-panel-${p.id}`}
          className={`${styles.panelTab} ${activePanel === p.id ? styles.panelTabActive : ''}`}
          onClick={() => onActivePanelChange(p.id)}
          data-testid={`connector-panel-tab-${p.id}`}
        >
          {p.label}
        </button>
      ))}
    </div>
    <p className={styles.panelHint}>
      {CONNECTOR_CONFIG_PANELS.find((p) => p.id === activePanel)?.hint}
    </p>

    {activePanel === 'connection' ? (
      <section className={styles.section} id="connector-panel-connection" role="tabpanel">
        <label className={styles.checkboxRow}>
          <input
            type="checkbox"
            checked={form.isEnabled}
            onChange={(e) => onFormChange((f) => ({ ...f, isEnabled: e.target.checked }))}
            data-testid="connector-enabled"
          />
          <ConnectorFieldLabel label="Bật connector" tooltip={CONNECTOR_FIELD_TOOLTIPS.enabled} />
        </label>
        <ConnectorFormField
          fieldId="connector-base-url"
          label="Base URL"
          tooltip={CONNECTOR_FIELD_TOOLTIPS.baseUrl}
          required
          value={form.externalBaseUrl ?? ''}
          onChange={(e) => onFormChange((f) => ({ ...f, externalBaseUrl: e.target.value }))}
          placeholder="https://foodmart-share-api.bosssoft.vn"
          data-testid="connector-base-url"
        />
        <ConnectorFormField
          fieldId="connector-api-key-header"
          label="Header API key"
          tooltip={CONNECTOR_FIELD_TOOLTIPS.apiKeyHeader}
          value={options.apiKeyHeader}
          onChange={(e) =>
            onOptionsChange((o) => ({ ...o, apiKeyHeader: e.target.value || 'x-api-key' }))
          }
        />
        <div className={styles.labeledField}>
          <ConnectorFieldLabel
            htmlFor="connector-api-key"
            label="API key"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.apiKey}
            required
          />
          <input
            id="connector-api-key"
            type="password"
            autoComplete="new-password"
            name={`connector-api-key-${configKey}`}
            value={apiKeyDisplayValue}
            onFocus={() => {
              if (showApiKeyMask) {
                setApiKeyEdited(true);
                onApiKeyInputChange('');
              }
            }}
            onChange={(e) => {
              setApiKeyEdited(true);
              onApiKeyInputChange(e.target.value);
            }}
            onInput={(e) => {
              setApiKeyEdited(true);
              onApiKeyInputChange((e.target as HTMLInputElement).value);
            }}
            placeholder={hasStoredApiKey ? undefined : 'Bắt buộc — lưu trên UI'}
            data-testid="connector-api-key-input"
          />
          <p
            className={`${styles.apiKeyHint} ${hasStoredApiKey || apiKeyInput ? styles.apiKeyHintOk : ''}`}
          >
            {apiKeyInput.trim() && !showApiKeyMask
              ? 'Sẽ gửi key mới khi Lưu / Test'
              : hasStoredApiKey
                ? 'Key đã lưu — click để thay key mới'
                : 'Chưa có key — nhập key REVA FM (x-api-key)'}
          </p>
        </div>
        <ConnectorFormField
          label="Search path (POST)"
          tooltip={CONNECTOR_FIELD_TOOLTIPS.searchPath}
          required
          value={options.searchPath}
          onChange={(e) => onOptionsChange((o) => ({ ...o, searchPath: e.target.value }))}
          placeholder="/api/RevaPlashform/TimHoaDon"
          data-testid="connector-search-path"
        />
        <ConnectorFormField
          label="Detail path (GET)"
          tooltip={CONNECTOR_FIELD_TOOLTIPS.detailPath}
          value={options.detailPathTemplate ?? ''}
          onChange={(e) =>
            onOptionsChange((o) => ({
              ...o,
              detailPathTemplate: e.target.value.replace(/\?.*$/, '').trim() || null,
            }))
          }
          placeholder="/api/RevaPlashform/ChiTietHoaDon"
        />
        <div className={styles.labeledField}>
          <ConnectorFieldLabel
            label="Query param detail"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.detailQueryParams}
          />
          <div className={styles.paramList}>
            {(options.detailQueryParams.length > 0 ? options.detailQueryParams : ['']).map(
              (param, index) => (
                <div key={`detail-param-${index}`} className={styles.paramRow}>
                  <input
                    className={styles.paramInput}
                    value={param}
                    placeholder={index === 0 ? 'billId' : 'documentNumber'}
                    onChange={(e) =>
                      onOptionsChange((o) => {
                        const next = [...(o.detailQueryParams.length > 0 ? o.detailQueryParams : [''])];
                        next[index] = e.target.value;
                        const cleaned = next.map((p) => p.trim()).filter(Boolean);
                        return {
                          ...o,
                          detailQueryParams: cleaned.length > 0 ? cleaned : [''],
                          detailKeyParam: cleaned[0] ?? o.detailKeyParam,
                        };
                      })
                    }
                    data-testid={index === 0 ? 'connector-detail-query-param' : undefined}
                  />
                  {options.detailQueryParams.length > 1 ? (
                    <Button
                      type="button"
                      variant="secondary"
                      onClick={() =>
                        onOptionsChange((o) => {
                          const next = o.detailQueryParams.filter((_, i) => i !== index);
                          return {
                            ...o,
                            detailQueryParams: next.length > 0 ? next : [''],
                            detailKeyParam: next[0] ?? 'billId',
                          };
                        })
                      }
                    >
                      Xóa
                    </Button>
                  ) : null}
                </div>
              ),
            )}
          </div>
          <Button
            type="button"
            variant="secondary"
            onClick={() =>
              onOptionsChange((o) => ({
                ...o,
                detailQueryParams: [...o.detailQueryParams.filter(Boolean), ''],
              }))
            }
          >
            + Thêm param
          </Button>
        </div>
        <div className={styles.grid2}>
          <ConnectorFormField
            label="Trường khóa document"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.documentKeyField}
            value={options.documentKeyField}
            onChange={(e) => onOptionsChange((o) => ({ ...o, documentKeyField: e.target.value }))}
          />
        </div>
        <label className={styles.checkboxRow}>
          <input
            type="checkbox"
            checked={options.fetchDetailBeforeImport}
            onChange={(e) =>
              onOptionsChange((o) => ({ ...o, fetchDetailBeforeImport: e.target.checked }))
            }
          />
          <ConnectorFieldLabel
            label="Gọi API detail trước khi import"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.fetchDetail}
          />
        </label>
      </section>
    ) : null}

    {activePanel === 'job' ? (
      <section className={styles.section} id="connector-panel-job" role="tabpanel">
        <div className={styles.grid2}>
          <ConnectorFormField
            label="Page size (sau probe)"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.pageSize}
            type="number"
            value={String(options.pageSize)}
            onChange={(e) => onOptionsChange((o) => ({ ...o, pageSize: Number(e.target.value) || 1 }))}
          />
          <ConnectorFormField
            label="Số job song song"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.parallelJobs}
            type="number"
            value={String(options.parallelJobs)}
            onChange={(e) =>
              onOptionsChange((o) => ({ ...o, parallelJobs: Number(e.target.value) || 1 }))
            }
          />
          <ConnectorFormField
            label="Timeout (giây)"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.timeoutSeconds}
            type="number"
            value={String(options.timeoutSeconds)}
            onChange={(e) =>
              onOptionsChange((o) => ({ ...o, timeoutSeconds: Number(e.target.value) || 60 }))
            }
          />
          <ConnectorFormField
            label="Số lần retry"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.maxRetries}
            type="number"
            value={String(options.maxRetries)}
            onChange={(e) => onOptionsChange((o) => ({ ...o, maxRetries: Number(e.target.value) || 3 }))}
          />
        </div>
      </section>
    ) : null}

    {activePanel === 'date' ? (
      <section className={styles.section} id="connector-panel-date" role="tabpanel">
        <p className={styles.datePriorityHint}>
          Ưu tiên: <strong>Từ/Đến mặc định</strong> → nếu trống dùng <strong>Offset + Lookback</strong>{' '}
          (theo timezone POS bên dưới).
        </p>
        <div className={styles.grid2}>
          <div className={styles.labeledField}>
            <ConnectorFieldLabel
              htmlFor="connector-source-timezone"
              label="Timezone POS / FM"
              tooltip={CONNECTOR_FIELD_TOOLTIPS.sourceTimezoneId}
            />
            <select
              id="connector-source-timezone"
              value={options.sourceTimezoneId ?? 'Asia/Ho_Chi_Minh'}
              style={{ width: '100%', padding: '8px 10px', fontSize: 14, borderRadius: 6, border: '1px solid #cbd5e1' }}
              onChange={(e) =>
                onOptionsChange((o) => ({
                  ...o,
                  sourceTimezoneId: e.target.value || 'Asia/Ho_Chi_Minh',
                }))
              }
              data-testid="connector-field-source-timezone"
            >
              {JOB_SCHEDULE_TIMEZONES.map((tz) => (
                <option key={tz.id} value={tz.id}>
                  {tz.label}
                </option>
              ))}
            </select>
          </div>
          <ConnectorFormField
            label="Từ ngày mặc định"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.defaultFromDate}
            type="date"
            value={options.defaultFromDate ?? ''}
            onChange={(e) =>
              onOptionsChange((o) => ({ ...o, defaultFromDate: e.target.value || null }))
            }
          />
          <ConnectorFormField
            label="Đến ngày mặc định"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.defaultToDate}
            type="date"
            value={options.defaultToDate ?? ''}
            onChange={(e) =>
              onOptionsChange((o) => ({ ...o, defaultToDate: e.target.value || null }))
            }
          />
          <ConnectorFormField
            label="Offset ngày"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.dateOffsetDays}
            type="number"
            value={String(options.dateOffsetDays)}
            onChange={(e) =>
              onOptionsChange((o) => ({ ...o, dateOffsetDays: Number(e.target.value) || 0 }))
            }
          />
          <ConnectorFormField
            label="Lookback (ngày)"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.syncLookbackDays}
            type="number"
            value={String(options.syncLookbackDays)}
            onChange={(e) =>
              onOptionsChange((o) => ({ ...o, syncLookbackDays: Number(e.target.value) || 1 }))
            }
          />
        </div>
      </section>
    ) : null}

    {activePanel === 'import' ? (
      <section className={styles.section} id="connector-panel-import" role="tabpanel">
        <ConnectorFormField
          label="Route import ERP"
          tooltip={CONNECTOR_FIELD_TOOLTIPS.endpointRoute}
          value={form.endpointRouteTemplate ?? ''}
          onChange={(e) => onFormChange((f) => ({ ...f, endpointRouteTemplate: e.target.value }))}
          placeholder="api/v1/… (để trống nếu chưa có endpoint)"
        />
      </section>
    ) : null}

    {activePanel === 'test' ? (
      <section
        className={`${styles.section} ${styles.testPanel}`}
        id="connector-panel-test"
        role="tabpanel"
      >
        <p className={styles.testIntro}>
          Test dùng draft hiện tại (kể cả API key chưa Lưu). Cần điền tab <strong>Kết nối</strong>{' '}
          trước. <strong>Preview convert</strong> — search + map field + xem chứng từ ERP (chưa ghi DB).
          Job sync chỉ dùng cấu hình <strong>đã Lưu</strong> — ngày Tạo sync phải trùng tab Test.
        </p>
        <div className={styles.grid2}>
          <ConnectorFormField
            label="Từ ngày test"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.testFromDate}
            type="date"
            value={testFromDate}
            onChange={(e) => onTestFromDateChange(e.target.value)}
            data-testid="connector-test-from-date"
          />
          <ConnectorFormField
            label="Đến ngày test"
            tooltip={CONNECTOR_FIELD_TOOLTIPS.testToDate}
            type="date"
            value={testToDate}
            onChange={(e) => onTestToDateChange(e.target.value)}
            data-testid="connector-test-to-date"
          />
        </div>
        <div className={styles.testActions}>
          <Button
            type="button"
            variant="secondary"
            onClick={onTestConnect}
            disabled={testingConnect || testingSearch || testingPreview}
            data-testid="connector-test-connect-btn"
          >
            {testingConnect ? 'Đang test…' : 'Test kết nối'}
          </Button>
          <Button
            type="button"
            variant="secondary"
            onClick={onTestSearch}
            disabled={testingConnect || testingSearch || testingPreview}
            data-testid="connector-test-search-btn"
          >
            {testingSearch ? 'Đang search…' : 'Test search data'}
          </Button>
          <Button
            type="button"
            onClick={onTestPreview}
            disabled={testingConnect || testingSearch || testingPreview}
            data-testid="connector-test-preview-btn"
          >
            {testingPreview ? 'Đang preview…' : 'Preview convert'}
          </Button>
          {onCreateSyncFromTest && canCreateSyncFromTest ? (
            <Button
              type="button"
              variant="secondary"
              onClick={onCreateSyncFromTest}
              disabled={testingConnect || testingSearch || testingPreview || !testFromDate || !testToDate}
              data-testid="connector-create-sync-from-test-btn"
            >
              Tạo sync (ngày test)
            </Button>
          ) : null}
        </div>
        {lastTestTotalItems !== undefined && lastTestTotalItems > 0 ? (
          <p className={styles.testMeta}>
            Lần test OK gần nhất: <strong>{lastTestTotalItems}</strong> chứng từ · {testFromDate} →{' '}
            {testToDate}
          </p>
        ) : null}
        {testResponse ? (
          <p className={styles.testMeta}>
            <strong>{testResponse.kind === 'connect' ? 'Test kết nối' : 'Test search'}:</strong>{' '}
            {testResponse.result.success ? 'Thành công' : 'Thất bại'}
            {testResponse.result.httpStatus ? ` · HTTP ${testResponse.result.httpStatus}` : ''}
            {' · '}
            {testResponse.result.elapsedMs} ms
            {testResponse.kind === 'search' && testResponse.result.success
              ? ` · ${testResponse.result.itemCount}/${testResponse.result.totalItems} items`
              : testResponse.kind === 'connect' && testResponse.result.success
                ? ` · totalItems: ${testResponse.result.totalItems}`
                : ''}
          </p>
        ) : null}
        {renderTestResponse(
          testResponse,
          configKey,
          () => toast.success('Đã copy — dán vào AI hoặc chat để phân tích'),
          () => toast.error('Không copy được — kiểm tra quyền clipboard trình duyệt'),
        )}
        {previewPanel}
      </section>
    ) : null}
  </div>
  );
};

export default ExternalConnectorConfigForm;
