import type { ExternalConnectorOptions } from '../../services/jobs';

const readRawString = (raw: Record<string, unknown>, ...names: string[]): string | null => {
  for (const name of names) {
    for (const [key, value] of Object.entries(raw)) {
      if (key.toLowerCase() !== name.toLowerCase()) continue;
      if (typeof value === 'string' && value.trim()) return value.trim();
    }
  }
  return null;
};

const readRawNumber = (raw: Record<string, unknown>, fallback: number, ...names: string[]): number => {
  for (const name of names) {
    for (const [key, value] of Object.entries(raw)) {
      if (key.toLowerCase() !== name.toLowerCase()) continue;
      if (typeof value === 'number' && !Number.isNaN(value)) return value;
    }
  }
  return fallback;
};

const readRawBool = (raw: Record<string, unknown>, fallback: boolean, ...names: string[]): boolean => {
  for (const name of names) {
    for (const [key, value] of Object.entries(raw)) {
      if (key.toLowerCase() !== name.toLowerCase()) continue;
      if (typeof value === 'boolean') return value;
    }
  }
  return fallback;
};

const readRawStringArray = (raw: Record<string, unknown>, ...names: string[]): string[] => {
  for (const name of names) {
    for (const [key, value] of Object.entries(raw)) {
      if (key.toLowerCase() !== name.toLowerCase()) continue;
      if (!Array.isArray(value)) continue;
      const list = value
        .filter((item): item is string => typeof item === 'string')
        .map((item) => item.trim())
        .filter(Boolean);
      if (list.length > 0) return list;
    }
  }
  return [];
};

/** Strip ?query from legacy detail path templates. */
export const detailPathOnly = (value?: string | null): string | null => {
  if (!value?.trim()) return null;
  const trimmed = value.trim().replace(/^['"]+|['"]+$/g, '');
  const q = trimmed.indexOf('?');
  const path = q >= 0 ? trimmed.slice(0, q) : trimmed;
  return path.replace(/\{id\}/gi, '').replace(/\/+$/, '') || null;
};

const extractQueryParamsFromLegacyPath = (value?: string | null): string[] => {
  if (!value?.trim()) return [];
  const q = value.indexOf('?');
  if (q < 0) return [];
  const query = value.slice(q + 1);
  const names: string[] = [];
  for (const segment of query.split('&')) {
    if (!segment) continue;
    const eq = segment.indexOf('=');
    const name = (eq >= 0 ? segment.slice(0, eq) : segment).trim();
    if (!name || name.toLowerCase() === '{id}') continue;
    names.push(name);
  }
  return names;
};

const syncDetailKeyParam = (params: string[], fallback: string): string[] => {
  const cleaned = params.map((p) => p.trim()).filter(Boolean);
  if (cleaned.length > 0) return cleaned;
  return fallback.trim() ? [fallback.trim()] : [];
};

export const defaultConnectorOptions = (): ExternalConnectorOptions => ({
  searchPath: '',
  detailPathTemplate: null,
  documentKeyField: 'soHoaDon',
  detailQueryParams: ['billId'],
  detailKeyParam: 'billId',
  pageSize: 100,
  parallelJobs: 4,
  timeoutSeconds: 60,
  maxRetries: 3,
  dateOffsetDays: 0,
  syncLookbackDays: 1,
  defaultFromDate: null,
  defaultToDate: null,
  sourceTimezoneId: 'Asia/Ho_Chi_Minh',
  apiKeyHeader: 'x-api-key',
  apiKey: null,
  apiKeyConfigKey: null,
  fetchDetailBeforeImport: true,
});

export const parseConnectorOptions = (json?: string | null): ExternalConnectorOptions => {
  if (!json) return defaultConnectorOptions();
  try {
    const raw = JSON.parse(json) as Record<string, unknown>;
    const defaults = defaultConnectorOptions();
    const rawDetailPath = readRawString(raw, 'detailPathTemplate');
    const legacyParams = extractQueryParamsFromLegacyPath(rawDetailPath);
    const fromArray = readRawStringArray(raw, 'detailQueryParams');
    const legacyKey = readRawString(raw, 'detailKeyParam') ?? defaults.detailKeyParam;
    const detailQueryParams = syncDetailKeyParam(
      fromArray.length > 0 ? fromArray : legacyParams,
      legacyKey,
    );

    return {
      searchPath: readRawString(raw, 'searchPath') ?? defaults.searchPath,
      detailPathTemplate: detailPathOnly(rawDetailPath),
      documentKeyField: readRawString(raw, 'documentKeyField') ?? defaults.documentKeyField,
      detailQueryParams,
      detailKeyParam: detailQueryParams[0] ?? legacyKey,
      pageSize: readRawNumber(raw, defaults.pageSize, 'pageSize'),
      parallelJobs: readRawNumber(raw, defaults.parallelJobs, 'parallelJobs'),
      timeoutSeconds: readRawNumber(raw, defaults.timeoutSeconds, 'timeoutSeconds'),
      maxRetries: readRawNumber(raw, defaults.maxRetries, 'maxRetries'),
      dateOffsetDays: readRawNumber(raw, defaults.dateOffsetDays, 'dateOffsetDays'),
      syncLookbackDays: readRawNumber(raw, defaults.syncLookbackDays, 'syncLookbackDays'),
      defaultFromDate: readRawString(raw, 'defaultFromDate'),
      defaultToDate: readRawString(raw, 'defaultToDate'),
      sourceTimezoneId: readRawString(raw, 'sourceTimezoneId') ?? defaults.sourceTimezoneId,
      apiKeyHeader: readRawString(raw, 'apiKeyHeader') ?? defaults.apiKeyHeader,
      apiKey: readRawString(raw, 'apiKey'),
      apiKeyConfigKey: readRawString(raw, 'apiKeyConfigKey'),
      fetchDetailBeforeImport: readRawBool(raw, defaults.fetchDetailBeforeImport, 'fetchDetailBeforeImport'),
    };
  } catch {
    return defaultConnectorOptions();
  }
};

export const serializeConnectorOptions = (options: ExternalConnectorOptions): string => {
  const sanitized = sanitizeConnectorOptions(options);
  const payload: Record<string, unknown> = {
    searchPath: sanitized.searchPath,
    detailPathTemplate: sanitized.detailPathTemplate,
    documentKeyField: sanitized.documentKeyField,
    detailKeyParam: sanitized.detailKeyParam,
    detailQueryParams: sanitized.detailQueryParams,
    pageSize: sanitized.pageSize,
    parallelJobs: sanitized.parallelJobs,
    timeoutSeconds: sanitized.timeoutSeconds,
    maxRetries: sanitized.maxRetries,
    dateOffsetDays: sanitized.dateOffsetDays,
    syncLookbackDays: sanitized.syncLookbackDays,
    defaultFromDate: sanitized.defaultFromDate ?? null,
    defaultToDate: sanitized.defaultToDate ?? null,
    sourceTimezoneId: sanitized.sourceTimezoneId?.trim() || 'Asia/Ho_Chi_Minh',
    apiKeyHeader: sanitized.apiKeyHeader,
    fetchDetailBeforeImport: sanitized.fetchDetailBeforeImport,
  };
  if (sanitized.apiKey?.trim()) {
    payload.apiKey = sanitized.apiKey.trim();
  }
  return JSON.stringify(payload);
};

const trimPath = (value: string): string =>
  value.trim().replace(/^['"]+|['"]+$/g, '');

export const sanitizeConnectorOptions = (
  options: ExternalConnectorOptions,
): ExternalConnectorOptions => {
  const detailQueryParams = syncDetailKeyParam(
    options.detailQueryParams ?? [],
    options.detailKeyParam ?? 'billId',
  );
  const pathRaw = options.detailPathTemplate ? trimPath(options.detailPathTemplate) : '';
  const pathOnly = detailPathOnly(pathRaw);

  return {
    ...options,
    searchPath: trimPath(options.searchPath ?? ''),
    detailPathTemplate: pathOnly,
    documentKeyField: (options.documentKeyField ?? 'soHoaDon').trim(),
    detailQueryParams,
    detailKeyParam: detailQueryParams[0] ?? 'billId',
    apiKeyHeader: (options.apiKeyHeader ?? 'x-api-key').trim() || 'x-api-key',
  };
};

export const computeRangeFromOffset = (opt: ExternalConnectorOptions): { from: string; to: string } => {
  const tz = opt.sourceTimezoneId?.trim() || 'Asia/Ho_Chi_Minh';
  const fmtLocal = (d: Date) =>
    new Intl.DateTimeFormat('en-CA', { timeZone: tz }).format(d);

  const todayLocal = fmtLocal(new Date());
  const to = addCalendarDays(todayLocal, -(opt.dateOffsetDays ?? 0));
  const from = addCalendarDays(to, -Math.max(0, (opt.syncLookbackDays ?? 1) - 1));
  return { from, to };
};

/** yyyy-MM-dd ± days in calendar (no TZ drift). */
const addCalendarDays = (isoDate: string, deltaDays: number): string => {
  const [y, m, d] = isoDate.split('-').map(Number);
  const dt = new Date(Date.UTC(y, m - 1, d));
  dt.setUTCDate(dt.getUTCDate() + deltaDays);
  return dt.toISOString().slice(0, 10);
};

export const resolveInitialSyncRange = (
  opt: ExternalConnectorOptions,
): { from: string; to: string } | null => {
  if (opt.defaultFromDate && opt.defaultToDate) {
    return { from: opt.defaultFromDate, to: opt.defaultToDate };
  }
  if (opt.dateOffsetDays !== undefined || opt.syncLookbackDays !== undefined) {
    return computeRangeFromOffset(opt);
  }
  return null;
};

export type SyncDateRange = { from: string; to: string };

/** Ưu tiên: override (test/modal) → lần test search OK gần nhất → default/offset. */
export const resolveSyncDateRange = (
  opt: ExternalConnectorOptions,
  override?: SyncDateRange | null,
  lastSuccessfulTest?: SyncDateRange | null,
): { from: string; to: string; source: 'override' | 'lastTest' | 'default' | 'offset' } | null => {
  if (override?.from && override?.to) {
    return { from: override.from, to: override.to, source: 'override' };
  }
  if (lastSuccessfulTest?.from && lastSuccessfulTest?.to) {
    return { from: lastSuccessfulTest.from, to: lastSuccessfulTest.to, source: 'lastTest' };
  }
  if (opt.defaultFromDate && opt.defaultToDate) {
    return { from: opt.defaultFromDate, to: opt.defaultToDate, source: 'default' };
  }
  if (opt.dateOffsetDays !== undefined || opt.syncLookbackDays !== undefined) {
    const range = computeRangeFromOffset(opt);
    return { ...range, source: 'offset' };
  }
  return null;
};

export const stripApiKeyFromOptions = (
  opt: ExternalConnectorOptions,
): { options: ExternalConnectorOptions; hasStoredApiKey: boolean } => {
  const hasStoredApiKey = Boolean(opt.apiKey?.trim());
  return {
    hasStoredApiKey,
    options: {
      ...opt,
      apiKey: null,
      apiKeyConfigKey: null,
    },
  };
};

export const API_KEY_MASK = '••••••••••••';

export const isApiKeyMaskValue = (value: string): boolean =>
  value === API_KEY_MASK || /^•+$/.test(value);

export const resolveApiKeyForPayload = (
  apiKeyInput: string,
  existingJson?: string | null,
  hasStoredApiKey = false,
): string | null => {
  const typed = apiKeyInput.trim();
  if (typed && !isApiKeyMaskValue(typed)) return typed;
  if (hasStoredApiKey) return null;
  return parseConnectorOptions(existingJson).apiKey?.trim() || null;
};

export const buildOptionsForSave = (
  options: ExternalConnectorOptions,
  apiKeyInput: string,
  existingJson?: string | null,
  hasStoredApiKey = false,
): ExternalConnectorOptions => {
  const sanitized = sanitizeConnectorOptions(options);
  const resolvedKey = resolveApiKeyForPayload(apiKeyInput, existingJson, hasStoredApiKey);
  const payload: ExternalConnectorOptions = {
    ...sanitized,
    apiKeyConfigKey: null,
  };
  if (resolvedKey) {
    payload.apiKey = resolvedKey;
  } else {
    delete payload.apiKey;
  }
  return payload;
};

export type ConnectorValidationResult = { ok: true } | { ok: false; message: string };

export const validateConnectorDateDefaults = (
  options: ExternalConnectorOptions,
): ConnectorValidationResult => {
  const from = options.defaultFromDate?.trim();
  const to = options.defaultToDate?.trim();
  if (!from && !to) return { ok: true };
  if (Boolean(from) !== Boolean(to)) {
    return { ok: false, message: 'Cần nhập cả Từ ngày và Đến ngày mặc định (hoặc để trống cả hai)' };
  }
  if (!from || !to) return { ok: true };

  const fromDate = new Date(from);
  const toDate = new Date(to);
  if (Number.isNaN(fromDate.getTime()) || Number.isNaN(toDate.getTime())) {
    return { ok: false, message: 'Ngày mặc định không hợp lệ' };
  }
  if (fromDate.getFullYear() < 2000 || toDate.getFullYear() < 2000) {
    return { ok: false, message: 'Năm ngày mặc định phải từ 2000 trở lên' };
  }
  if (from > to) {
    return { ok: false, message: 'Từ ngày mặc định không được lớn hơn Đến ngày' };
  }
  return { ok: true };
};

export const validateConnectionDraft = (
  externalBaseUrl: string | null | undefined,
  options: ExternalConnectorOptions,
  apiKeyInput: string,
  existingJson?: string | null,
  hasStoredApiKey = false,
): ConnectorValidationResult => {
  if (!externalBaseUrl?.trim()) {
    return { ok: false, message: 'Base URL là bắt buộc' };
  }
  const sanitized = sanitizeConnectorOptions(options);
  if (!sanitized.searchPath?.trim()) {
    return { ok: false, message: 'Search path là bắt buộc' };
  }
  if (sanitized.fetchDetailBeforeImport) {
    if (!sanitized.detailPathTemplate?.trim()) {
      return { ok: false, message: 'Detail path là bắt buộc khi bật gọi API detail' };
    }
    if (sanitized.detailPathTemplate.includes('?')) {
      return { ok: false, message: 'Detail path chỉ ghi URL — query param khai báo ở danh sách bên dưới' };
    }
    if (sanitized.detailQueryParams.length === 0) {
      return { ok: false, message: 'Thêm ít nhất 1 query param detail (giá trị = document key)' };
    }
    if (
      sanitized.searchPath.toLowerCase().includes('timphieu')
      && sanitized.detailQueryParams.some((p) => p.toLowerCase() === 'billid')
    ) {
      return {
        ok: false,
        message: 'Phiếu thu/chi: query param phải là documentNumber, không dùng billId',
      };
    }
  }
  const merged = buildOptionsForSave(sanitized, apiKeyInput, existingJson, hasStoredApiKey);
  if (!merged.apiKey && !hasStoredApiKey) {
    return { ok: false, message: 'API key là bắt buộc — nhập key mới hoặc lưu key trước đó' };
  }
  return validateConnectorDateDefaults(sanitized);
};
